#!/usr/bin/env bash
set -Eeuo pipefail

# Run this on the Proxmox host as root.
#
# TrueNAS Bacmaster's NAS UI branding v7.
# Modes:
#   apply   - stronger login wallpaper + top-left app logo overlay + safer visible text branding
#   restore - remove injected branding from index.html
#
# This only touches TrueNAS WebUI static files. No pools/datasets/services/settings are changed.

MODE="${1:-apply}"
case "$MODE" in
  apply|restore) ;;
  *)
    echo "Usage: $0 [apply|restore]"
    exit 2
    ;;
esac

TRUENAS_IP="${TRUENAS_IP:-192.168.50.101}"

source /root/homelab-secrets/truenas-login.env 2>/dev/null || true

TRUENAS_USER="${TRUENAS_SSH_USER:-truenas_admin}"
TRUENAS_PASS="${TRUENAS_SSH_PASS:-}"

if [[ -z "${TRUENAS_PASS}" ]]; then
  echo "TrueNAS SSH/sudo password gerekli."
  read -rsp "TrueNAS password: " TRUENAS_PASS
  echo
fi

if ! command -v sshpass >/dev/null 2>&1; then
  echo "sshpass yok; kuruluyor..."
  apt-get update
  apt-get install -y sshpass
fi

remote_sudo() {
  local remote_mode
  remote_mode="$(printf '%q' "$MODE")"
  {
    printf '%s\n' "$TRUENAS_PASS"
    cat
  } | SSHPASS="$TRUENAS_PASS" sshpass -e ssh \
    -o StrictHostKeyChecking=no \
    -o UserKnownHostsFile=/dev/null \
    "$TRUENAS_USER@$TRUENAS_IP" \
    "sudo -S -p '' env BACMASTERS_MODE=$remote_mode bash -s"
}

echo
echo "==> TrueNAS Bacmaster's NAS UI branding v7: $MODE"

remote_sudo <<'REMOTE'
set -Eeuo pipefail

MODE="${BACMASTERS_MODE:-apply}"
WEBUI="/usr/share/truenas/webui"
INDEX="$WEBUI/index.html"
BRAND_DIR="$WEBUI/bacmasters-brand"
JS="$BRAND_DIR/bacmasters-nas-branding.js"
CSS="$BRAND_DIR/bacmasters-nas-branding.css"
LOGO="$BRAND_DIR/bacmasters-nas-logo-transparent.png"
BG="$BRAND_DIR/bacmasters-nas-login-background.png"
STATE="/tmp/bacmasters-nas-v7-remounted-ro.txt"

: > "$STATE"

if [[ ! -f "$INDEX" ]]; then
  echo "ERROR: index.html not found: $INDEX"
  exit 10
fi

mapfile -t MPS < <(
  for p in / /usr /usr/share "$WEBUI"; do
    findmnt -T "$p" -no TARGET 2>/dev/null || true
  done | awk 'NF && !seen[$0]++'
)

for mp in "${MPS[@]}"; do
  opts="$(findmnt -no OPTIONS "$mp" 2>/dev/null || true)"
  if echo ",$opts," | grep -q ',ro,'; then
    echo "Remount RW: $mp"
    if mount -o remount,rw "$mp"; then
      echo "$mp" >> "$STATE"
    else
      echo "WARN: remount rw failed for $mp"
    fi
  fi
done

if ! touch "$WEBUI/.bacmasters-v7-write-test" 2>/dev/null; then
  echo "ERROR: WebUI is still not writable."
  exit 20
fi
rm -f "$WEBUI/.bacmasters-v7-write-test"

backup="/root/bacmasters-nas-webui-backups/v7-${MODE}-$(date +%Y%m%d-%H%M%S)"
mkdir -p "$backup"
cp -a "$INDEX" "$backup/index.html"
[[ -f "$JS" ]] && cp -a "$JS" "$backup/bacmasters-nas-branding.js"
[[ -f "$CSS" ]] && cp -a "$CSS" "$backup/bacmasters-nas-branding.css"
[[ -f "$LOGO" ]] && cp -a "$LOGO" "$backup/bacmasters-nas-logo-transparent.png"
[[ -f "$BG" ]] && cp -a "$BG" "$backup/bacmasters-nas-login-background.png"
echo "Backup: $backup"

if [[ "$MODE" == "restore" ]]; then
  python3 - "$INDEX" <<'PY'
from pathlib import Path
import re
import sys

p = Path(sys.argv[1])
s = p.read_text(errors="ignore")
s = re.sub(
    r'\n?<!-- BACMASTERS_NAS_BRANDING_START -->.*?<!-- BACMASTERS_NAS_BRANDING_END -->\n?',
    '\n',
    s,
    flags=re.S,
)
p.write_text(s)
PY

  systemctl reload nginx 2>/dev/null || systemctl restart nginx 2>/dev/null || true

  if [[ -s "$STATE" ]]; then
    tac "$STATE" | while read -r mp; do
      [[ -z "$mp" ]] && continue
      echo "Remount RO: $mp"
      mount -o remount,ro "$mp" 2>/dev/null || echo "WARN: could not remount RO: $mp"
    done
  fi

  echo "OK: Bacmaster branding injection removed from index.html."
  exit 0
fi

mkdir -p "$BRAND_DIR"

cat > "$LOGO.b64" <<'B64LOGO'

B64LOGO
base64 -d "$LOGO.b64" > "$LOGO"
rm -f "$LOGO.b64"

cat > "$BG.b64" <<'B64BG'

B64BG
base64 -d "$BG.b64" > "$BG"
rm -f "$BG.b64"

cat > "$JS" <<'JS'
(function () {
  'use strict';

  var TITLE = "Bacmaster's NAS";
  var LOGO = '/ui/bacmasters-brand/bacmasters-nas-logo-transparent.png?v=bacmasters-nas-v7';
  var BG = '/ui/bacmasters-brand/bacmasters-nas-login-background.png?v=bacmasters-nas-v7';
  var tries = 0;
  var maxTries = 180;
  var timer = null;
  var observerStarted = false;
  var domBrandingQueued = false;
  var periodicPasses = 0;
  var periodicTimer = null;

  function isLoginRoute() {
    var path = String(window.location.pathname || '').toLowerCase();
    return path.indexOf('signin') !== -1 || path.indexOf('login') !== -1;
  }

  function visible(el) {
    if (!el || !el.getBoundingClientRect) return false;
    var r = el.getBoundingClientRect();
    var s = window.getComputedStyle(el);
    return r.width > 20 && r.height > 20 && s.display !== 'none' && s.visibility !== 'hidden' && Number(s.opacity || 1) !== 0;
  }

  function findPasswordInput() {
    return document.querySelector('input[type="password"], input[name*="password" i]');
  }

  function ensureLoginBackgroundLayer() {
    var existing = document.getElementById('bacmasters-nas-page-bg');

    if (!isLoginRoute()) {
      if (existing && existing.parentNode) existing.parentNode.removeChild(existing);
      document.body.classList.remove('bacmasters-nas-login');
      return;
    }

    document.body.classList.add('bacmasters-nas-login');

    if (!existing) {
      existing = document.createElement('div');
      existing.id = 'bacmasters-nas-page-bg';
      existing.setAttribute('aria-hidden', 'true');
      document.body.insertBefore(existing, document.body.firstChild);
    }

    existing.style.backgroundImage =
      "linear-gradient(rgba(0,0,0,.10), rgba(0,0,0,.38)), url('" + BG + "')";
  }

  function makeLoginFullscreenLayersTransparent() {
    if (!isLoginRoute() || !document.body) return;

    var vw = Math.max(document.documentElement.clientWidth || 0, window.innerWidth || 0);
    var vh = Math.max(document.documentElement.clientHeight || 0, window.innerHeight || 0);
    var els = Array.prototype.slice.call(document.body.querySelectorAll('app-root, ix-root, router-outlet, div, main, section')).slice(0, 700);

    els.forEach(function (el) {
      if (!el || el.id === 'bacmasters-nas-page-bg') return;
      if (el.querySelector && el.querySelector('input[type="password"]')) return;

      var r = el.getBoundingClientRect();
      if (r.width >= vw * 0.72 && r.height >= vh * 0.72) {
        var bg = window.getComputedStyle(el).backgroundColor;
        if (bg && bg !== 'rgba(0, 0, 0, 0)' && bg !== 'transparent') {
          el.classList.add('bacmasters-nas-transparent-bg');
        }
      }
    });
  }

  function findLoginRoot(pass) {
    var el = pass;
    var best = null;

    for (var i = 0; i < 18 && el; i++) {
      var tag = (el.tagName || '').toLowerCase();
      if (tag === 'body' || tag === 'html' || tag === 'app-root') break;

      var text = String(el.innerText || '').toLowerCase();
      var width = el.offsetWidth || 0;
      var height = el.offsetHeight || 0;
      var looksRight = text.indexOf('username') !== -1 && text.indexOf('password') !== -1;
      var reasonableCard = width >= 280 && width <= 900 && height >= 220;

      if (looksRight && reasonableCard) best = el;
      el = el.parentElement;
    }

    return best || pass.closest('form') || pass.parentElement;
  }

  function hasFormBits(el) {
    return !!(el && el.querySelector && el.querySelector('input, textarea, button, select'));
  }

  function textOrAssetLooksTrueNas(el) {
    if (!el) return false;

    var text = String(el.innerText || el.textContent || '').toLowerCase();
    if (text.indexOf('truenas') !== -1) return true;

    if (el.querySelectorAll) {
      var imgs = Array.prototype.slice.call(el.querySelectorAll('img, svg, use, image'));
      for (var i = 0; i < imgs.length; i++) {
        var node = imgs[i];
        var attrText = '';
        if (node.getAttribute) {
          attrText =
            (node.getAttribute('src') || '') + ' ' +
            (node.getAttribute('href') || '') + ' ' +
            (node.getAttribute('xlink:href') || '') + ' ' +
            (node.getAttribute('alt') || '') + ' ' +
            (node.getAttribute('title') || '') + ' ' +
            (node.getAttribute('class') || '') + ' ' +
            (node.getAttribute('aria-label') || '');
        }

        var haystack = String(
          (node.src || '') + ' ' +
          ((node.href && node.href.baseVal) || '') + ' ' +
          attrText
        ).toLowerCase();

        if (haystack.indexOf('truenas') !== -1 || haystack.indexOf('logo') !== -1) return true;
      }
    }

    return false;
  }

  function mostlyAbovePassword(el, pass) {
    var er = el.getBoundingClientRect();
    var pr = pass.getBoundingClientRect();
    return er.bottom <= pr.top + 18 && er.top < pr.top;
  }

  function findOriginalBanner(root, pass) {
    var candidates = [];
    var rootRect = root.getBoundingClientRect();
    var all = Array.prototype.slice.call(root.querySelectorAll('*'));
    var passRect = pass.getBoundingClientRect();

    for (var i = 0; i < all.length; i++) {
      var el = all[i];
      if (!visible(el)) continue;
      if (hasFormBits(el)) continue;
      if (!mostlyAbovePassword(el, pass)) continue;

      var r = el.getBoundingClientRect();
      if (r.width < 220 || r.height < 70) continue;
      if (r.left < rootRect.left - 8 || r.right > rootRect.right + 8) continue;

      var looks = textOrAssetLooksTrueNas(el);
      var topVisual = r.width >= rootRect.width * 0.65 && r.height >= 100 && r.height <= 360;

      if (!looks && !topVisual) continue;

      var distance = Math.max(0, passRect.top - r.bottom);
      var score = 0;
      score += looks ? 500 : 0;
      score += topVisual ? 250 : 0;
      score += Math.min(260, r.width) + Math.min(220, r.height);
      score -= distance;

      candidates.push({ el: el, score: score, area: r.width * r.height });
    }

    candidates.sort(function (a, b) {
      if (b.score !== a.score) return b.score - a.score;
      return b.area - a.area;
    });

    return candidates.length ? candidates[0].el : null;
  }

  function removePreviousExtraBlocks() {
    Array.prototype.slice.call(document.querySelectorAll('#bacmasters-nas-login-brand, .bacmasters-nas-login-brand, .bacmasters-nas-fallback-banner')).forEach(function (el) {
      if (el && el.parentNode) el.parentNode.removeChild(el);
    });

    Array.prototype.slice.call(document.querySelectorAll('.bacmasters-hidden-original-banner')).forEach(function (el) {
      el.classList.remove('bacmasters-hidden-original-banner');
      el.style.display = '';
    });
  }

  function isForbiddenTextParent(el) {
    if (!el) return true;
    var tag = (el.tagName || '').toUpperCase();
    return tag === 'SCRIPT' || tag === 'STYLE' || tag === 'TEXTAREA' || tag === 'INPUT' || tag === 'CODE' || tag === 'PRE';
  }

  function replaceVisibleTrueNasText(root) {
    if (!root || !window.NodeFilter) return;

    var walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
      acceptNode: function (node) {
        if (!node.nodeValue || node.nodeValue.indexOf('TrueNAS') === -1) return NodeFilter.FILTER_REJECT;
        if (isForbiddenTextParent(node.parentElement)) return NodeFilter.FILTER_REJECT;
        return NodeFilter.FILTER_ACCEPT;
      }
    });

    var node;
    var limit = 360;
    while ((node = walker.nextNode()) && limit-- > 0) {
      node.nodeValue = node.nodeValue
        .replace(/TrueNAS®/g, TITLE)
        .replace(/TrueNAS/g, TITLE);
    }
  }

  function replaceBrandAttributes(root) {
    var scope = root || document;
    if (!scope.querySelectorAll) return;

    Array.prototype.slice.call(scope.querySelectorAll('[title*="TrueNAS"], [aria-label*="TrueNAS"], img[alt*="TrueNAS"], svg[aria-label*="TrueNAS"]')).forEach(function (el) {
      ['title', 'aria-label', 'alt'].forEach(function (attr) {
        var val = el.getAttribute && el.getAttribute(attr);
        if (val && val.indexOf('TrueNAS') !== -1) {
          el.setAttribute(attr, val.replace(/TrueNAS®/g, TITLE).replace(/TrueNAS/g, TITLE));
        }
      });
    });
  }

  function installBrandInto(banner) {
    banner.classList.add('bacmasters-nas-original-banner-replaced');
    banner.setAttribute('aria-label', TITLE);
    banner.innerHTML = '<img class="bacmasters-nas-main-logo" src="' + LOGO + '" alt="' + TITLE + '">';
  }

  function fallbackInsertBrand(root, pass) {
    var brand = document.createElement('section');
    brand.className = 'bacmasters-nas-fallback-banner';
    brand.innerHTML = '<img class="bacmasters-nas-main-logo" src="' + LOGO + '" alt="' + TITLE + '">';

    var child = pass;
    while (child && child.parentElement && child.parentElement !== root) {
      child = child.parentElement;
    }

    if (child && child.parentNode === root) {
      root.insertBefore(brand, child);
    } else {
      root.insertBefore(brand, root.firstChild);
    }
  }

  function installTopbarBrand() {
    if (isLoginRoute() || !document.body) {
      var old = document.getElementById('bacmasters-nas-topbar-brand');
      if (old && old.parentNode) old.parentNode.removeChild(old);
      document.body.classList.remove('bacmasters-nas-app');
      return;
    }

    document.body.classList.add('bacmasters-nas-app');

    var brand = document.getElementById('bacmasters-nas-topbar-brand');
    if (!brand) {
      brand = document.createElement('a');
      brand.id = 'bacmasters-nas-topbar-brand';
      brand.href = '/ui/dashboard';
      brand.setAttribute('aria-label', TITLE);
      brand.innerHTML = '<img src="' + LOGO + '" alt="' + TITLE + '">';
      document.body.appendChild(brand);
    }
  }

  function patchLoginWhenReady() {
    try {
      document.title = TITLE;

      ensureLoginBackgroundLayer();

      if (!isLoginRoute()) return true;

      makeLoginFullscreenLayersTransparent();

      var pass = findPasswordInput();
      if (!pass) return false;

      var root = findLoginRoot(pass);
      if (!root) return false;

      root.classList.add('bacmasters-nas-card-root');

      removePreviousExtraBlocks();

      var banner = findOriginalBanner(root, pass);
      if (banner) {
        installBrandInto(banner);
      } else {
        fallbackInsertBrand(root, pass);
      }

      replaceVisibleTrueNasText(root);
      replaceBrandAttributes(root);
      return true;
    } catch (err) {
      console.warn('[Bacmaster NAS branding] login v7 skipped:', err);
      return true;
    }
  }

  function brandWholeUi() {
    try {
      document.title = TITLE;
      ensureLoginBackgroundLayer();
      installTopbarBrand();

      replaceVisibleTrueNasText(document.body);
      replaceBrandAttributes(document.body);
    } catch (err) {
      console.warn('[Bacmaster NAS branding] UI text pass skipped:', err);
    }
  }

  function queueWholeUiBranding() {
    if (domBrandingQueued) return;
    domBrandingQueued = true;
    setTimeout(function () {
      domBrandingQueued = false;
      brandWholeUi();
    }, 180);
  }

  function startObserver() {
    if (observerStarted || !document.body || !window.MutationObserver) return;
    observerStarted = true;

    var obs = new MutationObserver(function () {
      queueWholeUiBranding();
    });

    obs.observe(document.body, {
      childList: true,
      subtree: true,
      characterData: true,
      attributes: true,
      attributeFilter: ['title', 'aria-label', 'alt']
    });
  }

  function startPeriodicPasses() {
    if (periodicTimer) clearInterval(periodicTimer);
    periodicPasses = 0;
    periodicTimer = setInterval(function () {
      periodicPasses += 1;
      patchLoginWhenReady();
      brandWholeUi();
      if (periodicPasses >= 120) {
        clearInterval(periodicTimer);
        periodicTimer = null;
      }
    }, 1000);
  }

  function startLoginTimer() {
    if (timer) clearInterval(timer);
    tries = 0;
    timer = setInterval(function () {
      tries += 1;
      if (patchLoginWhenReady() || tries >= maxTries) {
        clearInterval(timer);
        timer = null;
      }
      queueWholeUiBranding();
    }, 350);

    setTimeout(function () {
      patchLoginWhenReady();
      brandWholeUi();
      startObserver();
      startPeriodicPasses();
    }, 0);
  }

  document.title = TITLE;

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', startLoginTimer);
  } else {
    startLoginTimer();
  }

  window.addEventListener('load', function () {
    patchLoginWhenReady();
    brandWholeUi();
    startObserver();
    startPeriodicPasses();
  });

  window.addEventListener('hashchange', startLoginTimer);
  window.addEventListener('popstate', startLoginTimer);
})();
JS

